class BankAccount:
    def __init__(self, account_holder, initial_balance=0):
        # Private attributes (name mangling with __)
        self.__account_holder = account_holder
        self.__balance = initial_balance
        self.__transaction_count = 0

    # Getter methods using property decorator
    @property
    def balance(self):
        return self.__balance

    @property
    def account_holder(self):
        return self.__account_holder

    # Setter with validation
    @balance.setter
    def balance(self, amount):
        if amount < 0:
            raise ValueError("Balance cannot be negative")
        self.__balance = amount

    def deposit(self, amount):
        if amount > 0:
            self.__balance += amount
            self.__transaction_count += 1
            return f"Deposited: {amount}, New Balance: {self.__balance}"
        return "Invalid deposit amount"

    def withdraw(self, amount):
        if amount > 0 and amount <= self.__balance:
            self.__balance -= amount
            self.__transaction_count += 1
            return f"Withdrawn: {amount}, New Balance: {self.__balance}"
        return "Insufficient funds or invalid amount"

    def get_transaction_count(self):
        return self.__transaction_count

# Create account object
account = BankAccount("Rahul Sharma", 5000)

# Access using property (getter)
print(f"Account Holder: {account.account_holder}")
print(f"Initial Balance: {account.balance}")

# Perform transactions
print(account.deposit(2000))
print(account.withdraw(1500))

# Modify balance using setter
account.balance = 6000
print(f"Updated Balance: {account.balance}")

print(f"Total Transactions: {account.get_transaction_count()}")
